# Mock database for demonstration purposes
users_db = {}
reports_db = {}

def solve(arg1: dict) -> dict:
    action = arg1.get('action')

    if action == 'createUser':
        username = arg1.get('username')
        email = arg1.get('email')
        password = arg1.get('password')

        if email in users_db:
            return {'status': 'error', 'message': 'Email already in use'}

        user_id = str(len(users_db) + 1)
        users_db[email] = {'username': username, 'email': email, 'password': password, 'userId': user_id}
        return {'status': 'success', 'message': 'User created successfully', 'userId': user_id}

    elif action == 'getUser':
        email = arg1.get('email')

        user = users_db.get(email)
        if user:
            return {'username': user['username'], 'email': user['email']}
        else:
            return {'status': 'error', 'message': 'User not found'}

    elif action == 'downloadReport':
        report_id = arg1.get('reportId')

        report_data = reports_db.get(report_id)
        if report_data:
            return {'status': 'success', 'message': 'Report downloaded successfully', 'reportData': report_data}
        else:
            return {'status': 'error', 'message': 'Report not found'}

    return None
